#include <bits/stdc++.h>
using namespace std;

long long n, d, k, f[500005], a[500005][2], q[500005], l = 0, r = 100005;

bool check(int g) {
    memset(f, -0x3f, sizeof(f));
    memset(q, 0, sizeof(q));
    long long x = max(d - g, (long long)1), s = d + g;
    long long head = 1, tail = 0, j = 0;
    f[0] = 0;

    for (long long i = 1; i <= n; i++) {
        while (a[i][0] - a[j][0] >= x && j < i) {
            if (f[j] > -99999999) {
                while (f[q[tail]] <= f[j] && head <= tail) tail--;
                q[++tail] = j;
            }
            j++;
        }
        while (a[i][0] - a[q[head]][0] > s && head <= tail) head++;

        if (head <= tail) f[i] = f[q[head]] + a[i][1];
        if (f[i] >= k) return true;
    }
    return false;
}

int main() {
    cin >> n >> d >> k;
    for (long long i = 1; i <= n; i++) cin >> a[i][0] >> a[i][1];

    while (l < r) {
        long long mid = (l + r) >> 1;
        if (check(mid)) r = mid;
        else l = mid + 1;
    }

    if (l == 100005) cout << -1;
    else cout << l;

    return 0;
}
